VALUES
  ('social-worker-moex-03211', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依照「社會團體財務處理辦法」的規定，下列何者不是會計科目？', '["資產", "收入", "基金暨餘絀", "財產登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03212', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於「一個非營利組織為某一個人口群提供那些服務，滿足該人口群的那些需求？」是說明該組織的：', '["策略", "使命", "價值", "服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03213', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '彼得杜拉克提醒管理者：「你/妳不可能只僱用一雙手，你/妳僱用的一定是整個人。」這句話與下列那個 陳述中的意思不相關？', '["管理的工作沒有結束的一天", "管理者要尊重員工的差異性", "管理者應鼓勵員工自我管理", "做事的同仁比他所做的事情更重要"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03214', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在財務管理中，以量化（如金錢、方案量等）顯示在一個特定時間內某個非營利組織所計畫要進行的活 動，這稱為：', '["編列財務報表", "編列預算", "編列決算", "執行會計"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03215', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '高社會經濟地位在獲取資訊的方便性通常高於低社會經濟地位者，因此社會工作者運用資訊管理的能力 去教育低社會經濟地位人口群，這樣的努力稱為：', '["建立上網無障礙空間", "縮短數位落差", "倡導網路權益", "建立照顧服務便民入口網站"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03216', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在探討非營利組織內部結構時，如果注意到該組織依賴組織規章與程序，如操作手冊、作業程序等來規 範社工員的程度，這是注意到組織那一方面的狀況？', '["正式化（formalization）", "複雜化（complexity）", "集權化（centralization）", "部門化（departmentalization）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03217', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在改善績效中有一種積極的思維，鼓勵各組織與利害關係人一起回顧組織的風光年代，並共同思考可以 被期待的未來。透過願景分享，相互合作，此種方法稱為：', '["最佳價值", "肯定式探詢", "學習型組織", "優勢觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03218', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在績效考核中，評估者鼓勵員工說出自己對考核過程的意見，而且積極尋求員工關於如何改進考核系統 的意見，這是採取何種考核取向？', '["培力取向（empower approach）", "系統取向（system approach）", "夥伴取向（partnership approach）", "人際互動取向（human interaction approach）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03219', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織所建立的資訊系統涵括所有個案接受方案服務資料，以及各類型服務成果的變項等，並從此資料系 統建立成效指標，回答邁向目標的過程中所遇到的諸多問題，這是屬於何種類型的資訊管理系統？', '["人力資源資訊系統（human resource information system）", "成本導向系統（cost-directed system）", "績效導向系統（performance-directed system）", "行銷募款系統（marketing and fund-raising system）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03220', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織的行銷管理與營利組織有所差異，以下敘述何者為錯誤？', '["非營利組織的產品是指組織所提供的社會服務、理念或實體產品", "非營利組織在行銷時，貨幣價格是產品的主要考量因素", "非營利組織的推廣主要目的是在溝通，而非媒體操作", "非營利組織的服務通路是指輸送社會服務的地理區域、位置或時間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03221', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織採用「網絡定位策略」與其外在環境的各部門組織建立關係，關注的重點是「在此網絡關係 中，我們機構有否足以吸引其他機構的資源與能力？是否位居網絡的中心地位？」這是屬於下列何種決 策選擇？', '["介入程度", "移動彈性", "利益分配與核心程度", "競爭優勢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03222', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來社會服務機構在財務管理策略上，日趨採取對服務案主的收費以增加組織財務資源。若某一社會 服務機構是依據案主付費能力而定的收費方式，這是採取何種收費類型？', '["浮動支出（sliding-scale fees）", "參與支出（participation fees）", "固定支出（flat-rate fees）", "公平分攤支出（fair-share-cost fees）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03223', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在志工的招募上，基於市場區隔的各團體都有其獨特需要與興趣，所以需發展不同志工的職位與徵募消 息，這是運用何種行銷策略去獲取志工的人力資源？', '["無差異行銷", "差異行銷", "集中行銷", "聯合行銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03224', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織的領導者重視充權（empowerment）與個別化關懷，讓員工感受到自身任務的重要與個人成長，且能 激發員工為組織利益而非私人利益而努力，這是採取何種領導理論觀點？', '["特質理論（trait theory）", "行為理論（behavior theory）", "轉換型領導理論（transformational leadership theory）", "交易型領導理論（transactional leadership theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03225', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織的職務設計架構是依據主管想要藉著利用員工的知識、技能及創造潛能，以提高工作效能。此模式 建立在自發性與自制給予最大自由度的假設下，則可以達到能力運用的最佳化，這是屬於下列何種職務 設計模式？', '["傳統模式（the traditional model）", "人力資源模式（the human resources model）", "人群關係模式（the human relations model）", "科層制模式（the bureaucracy model）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03226', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在甄試員工的面試方法中，面試重點從應試者所具備的成就，轉移到他們是如何達到此成就，以指認應 試者所具備是達成此成就的技術或特質，這是何種面試法？', '["關鍵事件面試法（critical incident interviewing）", "模式化行為描述面試法（patterned behavior description interviewing）", "參與式面試法（participatory interviewing）", "能力為本面試法（competency-based interviewing）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03227', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Kettner 對於方案設計，從問題分析開始到需求評量，建立方案假設，發展出一套層級式之目的與目標， 且認為此層級式的方式具有許多益處，下列對此益處的陳述何者是錯誤的？', '["層級方法協助我們將重點置於問題的解決，而非僅為活動", "層級方法可以將方案活動和成果連結在一起", "層級方法僅能夠作為短程計畫的基礎", "層級方法提供我們一個架構，藉此作為後續監督與評估服務提供過程之用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03228', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「與其他地區所提供的服務做比較，您機構所服務的人口百分比是否較高或低？」的陳述，這是屬於下 列何種需求評量的類型？', '["規範性需求（normative need）", "相對性需求（relative need）", "感受性需求（perceived need）", "表達性需求（expressed need）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03229', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者進行方案評估時，採用「內部評估法」具有許多優點，但不包含下列那一項？', '["易於掌握組織結構與方案相關內容", "易於獲得主事者和員工的信任，進而讓他們承認問題和分享秘密", "豐富化服務品質的改善過程，有益於機構外部責信", "易於維持評估工作的客觀性與中立性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03230', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案進行績效評量，以「送餐到府」的方案為例，下列何者選項是「最終成果」績效評量的指標？', '["一個在接受服務後，能在家維持生活的服務對象", "一份送達時仍是溫熱的餐點", "一個維持充分營養的服務對象", "一份準時送達的餐點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03231', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來新公共管理主義發展所累積的效應已經產生一連串影響管理者的趨勢，但不包括下列那一項？', '["強調社會服務提供者之間的競爭會帶來更有效果的服務", "強調消費主義（consumerism），管理者需注重服務使用者的意見回饋", "強調組織的績效管理（performance management）", "強調擴大公部門對社會服務的提供"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03232', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者的角色若是評估組織的目標、預期結果、需要的技術，以及界定組織與方案的輸入、轉化、輸出 與結果，這是承擔下列何種的管理責任？', '["整體系統的分析", "使命與目標的建立", "理想結構的建立", "理想工作設計的建立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03233', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '從人群關係學派理論萃取出來可以應用於人群服務組織管理的有效原則，不包括下列那一項？', '["體認組織文化與其次文化的重要性", "體認正式結構與層級體系的重要性", "了解團體對個人表現的影響", "了解及應用有意義的獎勵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03234', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某類型的人群服務機構，其組織是依據特定領域的專門知識決定結構，例如營業部門負責臨床服務，人 力資源部門負責員工發展，這是採取何種部門化（departmentalization）的設計？', '["按方案部門化（departmentalization by program）", "按市場部門化（departmentalization by market）", "按功能部門化（departmentalization by function）", "按消費者/案主部門化（departmentalization by consumer/client）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03235', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在員工的考核評估中，評核者很容易因自己的某些缺點，而在考核時對受評者類似的缺點故意忽視，而 造成考核上的偏失，這是屬於何種員工考核評估的偏誤類型？', '["盲點效應（blindness effect）", "月暈效應（halo effect）", "尖角效應（horn effect）", "初始效應（primacy effect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
